import React, { useState } from "react";
import "./styles.css";
import InstructionModal from "./InstructionModal";

type Evaluation = {
  cultural: number | null;
  visual: number | null;
  hallucination: number | null;
};

type Props = {
  imageUrl: string;
  captions: string[];
  onSubmit: (allScores: Evaluation[]) => void;
};

export default function EvaluationPage({
  imageUrl,
  captions,
  onSubmit,
}: Props) {
  const [allScores, setAllScores] = useState<Evaluation[]>(
    captions.map(() => ({
      cultural: null,
      visual: null,
      hallucination: null,
    }))
  );

  const [showInstruction, setShowInstruction] = useState(false);

  const handleChange = (
    captionIdx: number,
    field: keyof Evaluation,
    value: number
  ) => {
    const updated = [...allScores];
    updated[captionIdx][field] = value;
    setAllScores(updated);
  };

  const handleSubmit = () => {
    const incomplete = allScores.some(
      (s) => !s.cultural || !s.visual || !s.hallucination
    );
    if (incomplete) {
      alert("Please complete all evaluations.");
      return;
    }

    onSubmit(allScores);
  };

  return (
    <div className="container">
      <div className="header">
        <h2 className="main-title">Image Evaluation</h2>
        <button
          className="instruction-button"
          onClick={() => setShowInstruction(true)}
        >
          📘 Instruction
        </button>
      </div>

      <img src={imageUrl} alt="evaluation" className="evaluation-image" />

      {captions.map((caption, index) => (
        <div key={index} className="caption-block">
          {index !== 0 && <hr className="caption-divider" />}
          <p className="caption">{caption}</p>

          <table className="rating-table">
            <thead>
              <tr>
                <th></th>
                {[1, 2, 3, 4, 5].map((n) => (
                  <th key={n}>{n}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {["cultural", "visual", "hallucination"].map((field) => (
                <tr key={field}>
                  <td>
                    {field === "cultural"
                      ? "Cultural Appropriateness"
                      : field === "visual"
                      ? "Visual Detail"
                      : "Hallucination"}
                  </td>
                  {[1, 2, 3, 4, 5].map((value) => (
                    <td key={value}>
                      <input
                        type="radio"
                        name={`${field}-${index}`}
                        value={value}
                        checked={
                          allScores[index][field as keyof Evaluation] === value
                        }
                        onChange={() =>
                          handleChange(index, field as keyof Evaluation, value)
                        }
                      />
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ))}

      <div className="button-wrapper spaced-buttons">
        <button
          className="next-button secondary"
          onClick={() => window.location.reload()}
        >
          Exit
        </button>
        <button className="next-button" onClick={handleSubmit}>
          Next Survey
        </button>
      </div>

      {showInstruction && (
        <InstructionModal onClose={() => setShowInstruction(false)} />
      )}
    </div>
  );
}
